@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: "Figtree", sans-serif;
}

.notes-modal {
  display: flex;
  flex-direction: column;
  padding: 0.5rem;
}

.notes-header {
  margin-bottom: 0.75rem;
}

.notes-title {
  font-size: 16px;
  font-weight: 700;
  color: #05042E;
}

.notes-list {
  overflow-y: auto;
  max-height: 280px;
  margin-bottom: 0.75rem;
}

.note-item {
  padding: 0.65rem 0;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.08);
}

.note-item:last-child {
  border-bottom: none;
}

.note-text {
  font-size: 13px;
  font-weight: 500;
  color: #05042E;
  line-height: 1.4;
}

.note-meta {
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: #888780;
  margin-top: 4px;
}

.notes-empty {
  text-align: center;
  color: #888780;
  font-size: 13px;
  font-weight: 500;
  padding: 1.5rem 0;
}

.notes-compose {
  border-top: 0.5px solid rgba(0, 0, 0, 0.08);
  padding-top: 0.75rem;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.notes-compose textarea {
  width: 100%;
  min-height: 64px;
  resize: vertical;
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  border-radius: 8px;
  padding: 8px 10px;
  font-family: "Figtree", sans-serif;
  font-size: 13px;
  color: #05042E;
  outline: none;
}

.notes-compose textarea::placeholder {
  color: #888780;
}

.notes-add-btn {
  align-self: flex-end;
  font-family: "Figtree", sans-serif;
  font-weight: 700;
  font-size: 12px;
  color: #05042E;
  background: #A3E851;
  border: none;
  border-radius: 6px;
  padding: 8px 16px;
  cursor: pointer;
}

.notes-add-btn:hover {
  background: #93d846;
}

