function escHtml(str) {
  return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
function render(model) {
  const notes = Array.isArray(model.notes) ? model.notes : [];
  const list = document.getElementById('notes-list');
  if (!notes.length) {
    list.innerHTML = '<div class="notes-empty">No notes yet.</div>';
    return;
  }
  list.innerHTML = notes.map(function (n) {
    return '<div class="note-item">' + '<div class="note-text">' + escHtml(n.note_text || '') + '</div>' + '<div class="note-meta">' + escHtml(n.created_by || '') + ' · ' + escHtml(n.created_at || '') + '</div>' + '</div>';
  }).join('');
}
window.addNote = function () {
  const input = document.getElementById('notes-input');
  const val = input.value;
  if (!val || !val.trim()) return;
  appsmith.updateModel({
    noteText: val
  });
  input.value = '';
  appsmith.triggerEvent('onAddNote');
};
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function (m) {
  render(m);
});

